import React, { createContext, useContext, useState, useEffect } from 'react';

interface LanguageContextType {
  language: 'pt' | 'en' | 'es';
  setLanguage: (lang: 'pt' | 'en' | 'es') => void;
}

const LanguageContext = createContext<LanguageContextType | null>(null);

export const LanguageProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [language, setLanguage] = useState<'pt' | 'en' | 'es'>(() => {
    // Try to get from localStorage first, then from AppContext if available
    const stored = localStorage.getItem('appState');
    if (stored) {
      try {
        const parsed = JSON.parse(stored);
        return parsed.language || 'pt';
      } catch {
        return 'pt';
      }
    }
    return 'pt';
  });

  const handleSetLanguage = (lang: 'pt' | 'en' | 'es') => {
    setLanguage(lang);
    // Also update AppContext state if available
    const stored = localStorage.getItem('appState');
    if (stored) {
      try {
        const parsed = JSON.parse(stored);
        parsed.language = lang;
        localStorage.setItem('appState', JSON.stringify(parsed));
        // Dispatch event to notify AppContext
        window.dispatchEvent(new CustomEvent('languageChange', { detail: lang }));
      } catch (error) {
        console.error('Error updating language:', error);
      }
    }
  };

  useEffect(() => {
    localStorage.setItem('language', language);

    // Trigger automatic translation when language changes
    if (typeof window !== 'undefined' && window.autoTranslator) {
      window.autoTranslator.setLanguage(language);
    }
  }, [language]);

  return (
    <LanguageContext.Provider value={{ language, setLanguage: handleSetLanguage }}>
      {children}
    </LanguageContext.Provider>
  );
};

export const useLanguage = () => {
  const context = useContext(LanguageContext);
  if (!context) {
    throw new Error('useLanguage must be used within a LanguageProvider');
  }
  return context;
};

// Add autoTranslator to window object
declare global {
  interface Window {
    autoTranslator?: any;
  }
}
